export const getCountry = (slug: string) => countries.find((c) => c.slug === slug);

// Cities helper for /countries/$slug/cities/$city
export const cityToSlug = (city: string) => city.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
export function getCityCountry(citySlug: string, countrySlug: string) {
  const country = getCountry(countrySlug);
  if (!country) return null;
  const city = country.topCities.find((c) => cityToSlug(c) === citySlug);
  if (!city) return null;
  return { country, city };
}

// Flat list of all (country, city) pairs — used by sitemap
export const allCityPairs = countries.flatMap((c) =>
  c.topCities.map((city) => ({ countrySlug: c.slug, citySlug: cityToSlug(city), country: c, city })),
);
